import React, { useState } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

const API = process.env.REACT_APP_API_URL || "http://192.168.7.12:5000/api";

export default function ScanPage() {
  const { token } = useParams();

  const [data, setData] = useState(null);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [verified, setVerified] = useState(false);

  const handleVerify = async () => {
    setVerified(true);
    setLoading(true);

    try {
      const res = await axios.get(`${API}/public/scan/${token}`);
      setData(res.data);
    } catch (err) {
      setError(err.response?.data?.error || "Failed to load emergency information");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(180deg, #0f172a, #020617)',
      padding: 20,
      color: 'white',
      fontFamily: 'sans-serif'
    }}>

      {/* Header */}
      <h1 style={{
        textAlign: 'center',
        color: '#ef4444',
        marginBottom: 20
      }}>
        🚨 Emergency Info
      </h1>

      {/* Verify Button */}
      {!verified && (
        <div style={{ textAlign: 'center', marginTop: 60 }}>
          <button
            onClick={handleVerify}
            style={{
              background: '#ef4444',
              padding: '14px 40px',
              border: 'none',
              borderRadius: 12,
              color: 'white',
              fontSize: 16,
              fontWeight: 'bold',
              boxShadow: '0 4px 20px rgba(239,68,68,0.4)'
            }}
          >
            🔐 Verify & View
          </button>
        </div>
      )}

      {/* Loading */}
      {loading && <p style={{ textAlign: 'center' }}>Loading...</p>}

      {/* Error */}
      {error && (
        <p style={{ textAlign: 'center', color: 'red' }}>{error}</p>
      )}

      {/* Profile Card */}
      {data && data.profile && (
        <div style={{
          background: '#1e293b',
          borderRadius: 16,
          padding: 20,
          marginTop: 20,
          boxShadow: '0 0 20px rgba(0,0,0,0.3)'
        }}>
          <h2 style={{ marginBottom: 10 }}>
            👤 {data.profile.full_name || "No Name"}
          </h2>

          <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
            {data.profile.gender && <span>👩 {data.profile.gender}</span>}
            {data.profile.date_of_birth && <span>🎂 {data.profile.date_of_birth}</span>}
            {data.profile.blood_type && (
              <span style={{
                color: '#ef4444',
                fontWeight: 'bold'
              }}>
                🩸 {data.profile.blood_type}
              </span>
            )}
            {data.profile.address && <span>📍 {data.profile.address}</span>}
          </div>
        </div>
      )}

      {/* Medical Info */}
      {data && data.profile && (
        <div style={{
          background: '#1e293b',
          borderRadius: 16,
          padding: 20,
          marginTop: 20
        }}>
          <h3>🏥 Medical Info</h3>

          <p>⚠️ {data.profile.allergies || "None"}</p>
          <p>🩺 {data.profile.medical_conditions || "None"}</p>
          <p>💊 {data.profile.current_medications || "None"}</p>

          {data.profile.doctor_name && (
            <p>👨‍⚕️ {data.profile.doctor_name}</p>
          )}
          {data.profile.doctor_phone && (
            <p>📞 {data.profile.doctor_phone}</p>
          )}
        </div>
      )}

      {/* Contacts */}
      {data && data.contacts && data.contacts.length > 0 && (
        <div style={{
          background: '#1e293b',
          borderRadius: 16,
          padding: 20,
          marginTop: 20
        }}>
          <h3>📞 Emergency Contacts</h3>

          {data.contacts.map((c) => (
            <div key={c.id} style={{
              marginTop: 10,
              padding: 10,
              borderRadius: 10,
              background: '#334155'
            }}>
              <p style={{ marginBottom: 5 }}>
                {c.name} ({c.relationship})
              </p>

              <a href={`tel:${c.phone}`}>
                <button style={{
                  background: '#ef4444',
                  border: 'none',
                  padding: '8px 20px',
                  borderRadius: 8,
                  color: 'white'
                }}>
                  📞 Call
                </button>
              </a>
            </div>
          ))}
        </div>
      )}

    </div>
  );
}
